function getStorage(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch { return fallback; }
}
function setStorage(key, val) {
  localStorage.setItem(key, JSON.stringify(val));
}

export function AuthProvider({ children }) {
  const [currentUser, setCurrentUser] = useState(() => getStorage('gig_user', null));
  const [users, setUsers] = useState(() => {
    const stored = getStorage('gig_users', null);
    const defaults = [...DEFAULT_WORKERS, DEFAULT_EMPLOYER];
    if (!stored || stored.length === 0) return defaults;
    // Ensure default workers and demo employer are always present
    const hasWorkers = stored.some(u => u.role === 'worker');
    const hasDemoEmployer = stored.some(u => u.id === 'e-demo');
    let list = stored;
    if (!hasWorkers) list = [...DEFAULT_WORKERS, ...list.filter(u => u.role !== 'worker')];
    if (!hasDemoEmployer) list = [DEFAULT_EMPLOYER, ...list.filter(u => u.id !== 'e-demo')];
    return list;
  });
  const [reviews, setReviews] = useState(() => getStorage('gig_reviews', DEFAULT_REVIEWS));
  const [jobs, setJobs] = useState(() => getStorage('gig_jobs', []));

  useEffect(() => { setStorage('gig_users', users); }, [users]);
  useEffect(() => { setStorage('gig_reviews', reviews); }, [reviews]);
  useEffect(() => { setStorage('gig_jobs', jobs); }, [jobs]);
  useEffect(() => { setStorage('gig_user', currentUser); }, [currentUser]);

  const login = (email, password, role) => {
    const user = users.find(u => u.email === email && u.password === password && u.role === role);
    if (!user) return { success: false, message: 'Invalid credentials or wrong role selected.' };
    setCurrentUser(user);
    return { success: true, user };
  };

  const register = (data) => {
    if (users.find(u => u.email === data.email)) {
      return { success: false, message: 'Email already registered.' };
    }
    const newUser = { ...data, id: `u_${Date.now()}`, jobsDone: 0 };
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
    return { success: true, user: newUser };
  };

  const logout = () => setCurrentUser(null);

  const updateUser = (updated) => {
    setUsers(prev => prev.map(u => u.id === updated.id ? updated : u));
    setCurrentUser(updated);
  };

  const getWorkers = (filters = {}) => {
    let list = users.filter(u => u.role === 'worker');
    if (filters.city) list = list.filter(w => w.city?.toLowerCase() === filters.city.toLowerCase());
    if (filters.locality) list = list.filter(w => w.locality?.toLowerCase().includes(filters.locality.toLowerCase()));
    if (filters.jobType) list = list.filter(w => w.jobType?.includes(filters.jobType));
    if (filters.skill) list = list.filter(w => w.skills?.some(s => s.toLowerCase().includes(filters.skill.toLowerCase())));
    if (filters.availability) list = list.filter(w => w.availability === filters.availability);
    return list;
  };

  const getWorkerById = (id) => users.find(u => u.id === id);

  const getReviewsForWorker = (workerId) => reviews.filter(r => r.workerId === workerId);

  const getAvgRating = (workerId) => {
    const wReviews = getReviewsForWorker(workerId);
    if (!wReviews.length) return 0;
    return (wReviews.reduce((sum, r) => sum + r.rating, 0) / wReviews.length).toFixed(1);
  };

  const addReview = (review) => {
    const newReview = { ...review, id: `rev_${Date.now()}`, date: new Date().toISOString().split('T')[0] };
    setReviews(prev => [...prev, newReview]);
    // Increment jobsDone for worker
    setUsers(prev => prev.map(u => u.id === review.workerId ? { ...u, jobsDone: (u.jobsDone || 0) + 1 } : u));
    return newReview;
  };

  const postJob = (jobData) => {
    const newJob = { ...jobData, id: `job_${Date.now()}`, status: 'open', createdAt: new Date().toISOString() };
    setJobs(prev => [...prev, newJob]);
    return newJob;
  };

  const getJobsForEmployer = (employerId) => jobs.filter(j => j.employerId === employerId);
  const getJobsForWorker = (workerId) => jobs.filter(j => j.workerId === workerId);

  const updateJobStatus = (jobId, status) => {
    setJobs(prev => prev.map(j => j.id === jobId ? { ...j, status } : j));
  };

  const getCities = () => [...new Set(users.filter(u => u.role === 'worker' && u.city).map(u => u.city))];
  const getLocalities = (city) => [...new Set(users.filter(u => u.role === 'worker' && u.city?.toLowerCase() === city?.toLowerCase() && u.locality).map(u => u.locality))];

  return (
    <AuthContext.Provider value={{
      currentUser, users, reviews, jobs,
      login, register, logout, updateUser,
      getWorkers, getWorkerById,
      getReviewsForWorker, getAvgRating, addReview,
      postJob, getJobsForEmployer, getJobsForWorker, updateJobStatus,
      getCities, getLocalities,
    }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);

import { useState, useMemo } from 'react';
import { useAuth } from '../context/AuthContext';
import WorkerCard from '../components/WorkerCard';
import ReviewModal from '../components/ReviewModal';
import { Search, MapPin, Filter, Briefcase, Home, Building2, SlidersHorizontal, X } from 'lucide-react';
import './EmployerDashboard.css';

const WORK_TYPE_OPTIONS = [
  { val: 'home',     label: 'Home / Personal', icon: <Home size={20}/>,      desc: 'Domestic help, repairs, cooking, cleaning for your home or family.', color: '#43e97b' },
  { val: 'business', label: 'Business Use',    icon: <Building2 size={20}/>, desc: 'Office support, logistics, construction, professional services.',       color: '#6c63ff' },
];

export default function EmployerDashboard() {
  const { currentUser, getWorkers, getCities, getLocalities } = useAuth();

  /* Work type selection */
  const [workType, setWorkType] = useState(null);

  /* Search / filter */
  const [city, setCity]           = useState('');
  const [locality, setLocality]   = useState('');
  const [skill, setSkill]         = useState('');
  const [availability, setAvailability] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  /* Review modal */
  const [reviewWorker, setReviewWorker] = useState(null);
  const [toast, setToast] = useState(null);

  const cities = getCities();
  const localities = city ? getLocalities(city) : [];

  const workers = useMemo(() => {
    if (!workType) return [];
    return getWorkers({ jobType: workType, city, locality, skill, availability });
  }, [workType, city, locality, skill, availability]);

  const showToast = (msg, type = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const clearFilters = () => { setCity(''); setLocality(''); setSkill(''); setAvailability(''); };

  if (!workType) {
    return (
      <div className="emp-page">
        <div className="emp-hero">
          <h1 className="emp-welcome">Hi, {currentUser?.name?.split(' ')[0]} ≡ƒæï</h1>
          <p className="emp-sub">What type of work do you need help with today?</p>
        </div>

        <div className="worktype-grid">
          {WORK_TYPE_OPTIONS.map(opt => (
            <button
              key={opt.val}
              id={`worktype-${opt.val}`}
              className="worktype-card glass-card"
              onClick={() => setWorkType(opt.val)}
            >
              <div className="worktype-icon" style={{ background: `${opt.color}22`, color: opt.color, border: `1px solid ${opt.color}44` }}>
                {opt.icon}
              </div>
              <h2 className="worktype-label">{opt.label}</h2>
              <p className="worktype-desc">{opt.desc}</p>
              <span className="worktype-cta" style={{ color: opt.color }}>Browse Workers ΓåÆ</span>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="emp-page">
      {/* Header */}
      <div className="emp-toolbar">
        <div className="emp-toolbar-left">
          <button id="back-worktype" className="btn btn-secondary btn-sm" onClick={() => setWorkType(null)}>
            ΓåÉ Change Type
          </button>
          <span className={`badge ${workType === 'home' ? 'badge-success' : 'badge-primary'}`} style={{ fontSize:'0.82rem', padding:'6px 14px' }}>
            {workType === 'home' ? '≡ƒÅá Home / Personal' : '≡ƒÅó Business'}
          </span>
          <span className="worker-count">{workers.length} worker{workers.length !== 1 ? 's' : ''} found</span>
        </div>
        <button
          id="toggle-filters"
          className={`btn btn-secondary btn-sm ${showFilters ? 'filter-active' : ''}`}
          onClick={() => setShowFilters(!showFilters)}
        >
          <SlidersHorizontal size={15}/> Filters
          {(city || skill || availability) && <span className="filter-dot"/>}
        </button>
      </div>

      {/* Filters Panel */}
      {showFilters && (
        <div className="filter-panel glass-card animate-fadeInUp">
          <div className="filter-row">
            <div className="form-group" style={{ minWidth:'180px' }}>
              <label className="form-label"><MapPin size={12} style={{ display:'inline', marginRight:'4px' }}/>City</label>
              <select id="filter-city" className="form-select" value={city} onChange={e => { setCity(e.target.value); setLocality(''); }}>
                <option value="">All Cities</option>
                {cities.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            {city && localities.length > 0 && (
              <div className="form-group" style={{ minWidth:'200px' }}>
                <label className="form-label">Locality</label>
                <select id="filter-locality" className="form-select" value={locality} onChange={e => setLocality(e.target.value)}>
                  <option value="">All Localities</option>
                  {localities.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
              </div>
            )}
            {city && localities.length === 0 && (
              <div className="form-group" style={{ minWidth:'200px' }}>
                <label className="form-label">Locality</label>
                <input id="filter-locality-input" type="text" className="form-input" placeholder="e.g. Kothrud"
                  value={locality} onChange={e => setLocality(e.target.value)} />
              </div>
            )}
            <div className="form-group" style={{ minWidth:'160px' }}>
              <label className="form-label">Skill</label>
              <input id="filter-skill" type="text" className="form-input" placeholder="e.g. Plumbing"
                value={skill} onChange={e => setSkill(e.target.value)} />
            </div>
            <div className="form-group" style={{ minWidth:'150px' }}>
              <label className="form-label">Availability</label>
              <select id="filter-availability" className="form-select" value={availability} onChange={e => setAvailability(e.target.value)}>
                <option value="">Any</option>
                <option value="available">Available Now</option>
                <option value="busy">Busy</option>
              </select>
            </div>
            {(city || skill || availability) && (
              <button className="btn btn-secondary btn-sm" style={{ alignSelf:'flex-end', marginBottom:'0' }} onClick={clearFilters}>
                <X size={13}/> Clear
              </button>
            )}
          </div>
        </div>
      )}

      {/* Workers Grid */}
      {workers.length === 0 ? (
        <div className="empty-state glass-card">
          <Search size={48} style={{ color:'rgba(240,240,255,0.2)', margin:'0 auto' }}/>
          <h3 style={{ marginTop:'16px', color:'rgba(240,240,255,0.6)' }}>No workers found</h3>
          <p style={{ fontSize:'0.85rem', color:'rgba(240,240,255,0.35)', marginTop:'8px' }}>
            Try changing the city or skill filter, or check back later.
          </p>
          {(city || skill || availability) && (
            <button className="btn btn-secondary btn-sm" style={{ marginTop:'16px' }} onClick={clearFilters}>Clear Filters</button>
          )}
        </div>
      ) : (
        <div className="workers-grid">
          {workers.map((w, i) => (
            <div key={w.id} style={{ animationDelay:`${i * 0.07}s` }}>
              <WorkerCard
                worker={w}
                showActions
                onHire={(worker) => {
                  // Open WhatsApp or show hire message
                  showToast(`Hire request sent to ${worker.name}! Check your messages.`);
                }}
                onReview={(worker) => setReviewWorker(worker)}
              />
            </div>
          ))}
        </div>
      )}

      {/* Review Modal */}
      {reviewWorker && (
        <ReviewModal
          worker={reviewWorker}
          onClose={() => setReviewWorker(null)}
          onSuccess={() => showToast(`Review submitted for ${reviewWorker.name}!`)}
        />
      )}

      {/* Toast */}
      {toast && (
        <div className={`toast toast-${toast.type}`}>{toast.msg}</div>
      )}
    </div>
  );
}
